DELIMITER $$
--
-- Events
--
CREATE DEFINER=`root`@`localhost` EVENT `prune_expired_non_called_out_events` ON SCHEDULE EVERY 1 DAY STARTS '2026-04-29 00:00:00' ON COMPLETION PRESERVE ENABLE DO DELETE FROM events
WHERE event_type != (
    SELECT event_type_id
    FROM event_types
    WHERE event_name = 'called_out'
    LIMIT 1
)
AND start_day < CURRENT_DATE$$

CREATE DEFINER=`root`@`localhost` EVENT `prune_expired_called_out_events` ON SCHEDULE EVERY 1 DAY STARTS '2026-04-29 00:00:00' ON COMPLETION PRESERVE ENABLE DO DELETE FROM events
WHERE event_type = (
    SELECT event_type_id
    FROM event_types
    WHERE event_name = 'called_out'
    LIMIT 1
)
AND final_day IS NOT NULL
AND final_day < CURRENT_DATE$$

CREATE DEFINER=`root`@`localhost` EVENT `prune_empty_schedule` ON SCHEDULE EVERY 1 DAY STARTS '2026-04-29 00:00:00' ON COMPLETION PRESERVE ENABLE DO DELETE FROM schedule
WHERE course_id IN (
    SELECT course_id
    FROM courses
    WHERE course_count <= 0
)$$

CREATE DEFINER=`root`@`localhost` EVENT `prune_empty_courses` ON SCHEDULE EVERY 1 DAY STARTS '2026-04-29 00:00:00' ON COMPLETION PRESERVE ENABLE DO DELETE FROM courses
WHERE course_count <= 0$$

CREATE DEFINER=`root`@`localhost` EVENT `prune_empty_subjects` ON SCHEDULE EVERY 1 DAY STARTS '2026-04-29 00:00:00' ON COMPLETION PRESERVE ENABLE DO DELETE FROM subjects
WHERE subject_count <= 0$$

CREATE DEFINER=`root`@`localhost` EVENT `prune_schedule_audit_logs` ON SCHEDULE EVERY 1 DAY STARTS '2026-04-29 00:00:00' ON COMPLETION PRESERVE ENABLE DO DELETE FROM log
WHERE table_name = 'schedule'
AND time_stamp < NOW() - INTERVAL 30 DAY$$

CREATE DEFINER=`root`@`localhost` EVENT `prune_general_audit_logs` ON SCHEDULE EVERY 1 DAY STARTS '2026-04-29 00:00:00' ON COMPLETION PRESERVE ENABLE DO DELETE FROM log
WHERE table_name != 'schedule'
AND time_stamp < NOW() - INTERVAL 365 DAY$$

DELIMITER ;
